+import type { Pattern } from './types/Pattern';
+import type { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type Clause = {
+  patterns: Pattern<any>[];
+  predicate?: (value: any) => unknown;
+  handler: (selection: unknown, value: any) => unknown;
+};
+
+type Entry = Clause | { tap: (result: unknown) => void };
+
+/**
+ * `matchEach` creates a pattern matching expression which runs every matching
+ * clause and returns their results in declaration order.
+ */
+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, output>;
+export function matchEach<input = unknown, output = symbols.unset>(): MatchEach<
+  input,
+  output
+>;
+export function matchEach(value?: unknown): MatchEach<any, any> {
+  return new MatchEachExpression(value, arguments.length > 0, [] as Entry[]) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private input: input,
+    private hasInput: boolean,
+    private entries: readonly Entry[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, -1));
+    }
+
+    return new MatchEachExpression(this.input, this.hasInput, [
+      ...this.entries,
+      { patterns, predicate, handler },
+    ]);
+  }
+
+  when(predicate: (value: input) => unknown, handler: (value: input) => output) {
+    return new MatchEachExpression(this.input, this.hasInput, [
+      ...this.entries,
+      { patterns: [symbols.matcher], predicate, handler: (_: unknown, value: input) => handler(value) },
+    ]);
+  }
+
+  tap(callback: (result: output) => void) {
+    return new MatchEachExpression(this.input, this.hasInput, [
+      ...this.entries,
+      { tap: callback },
+    ]);
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const results = this.evaluate(this.input);
+    return results.length === 0 ? [handler(this.input)] : results;
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
+    const results = this.evaluate(this.input);
+    return results.length === 0 ? [unexpectedValueHandler(this.input)] : results;
+  }
+
+  run(): output[] {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    return (value: input): output[] => this.evaluateOrThrow(value);
+  }
+
+  toExhaustiveFunction() {
+    return (value: input): output[] => this.evaluateOrThrow(value);
+  }
+
+  toPartialFunction() {
+    return (value: input): output[] | undefined => {
+      const results = this.evaluate(value);
+      return results.length === 0 ? undefined : results;
+    };
+  }
+
+  private evaluateOrThrow(value: input): output[] {
+    const results = this.evaluate(value);
+    if (results.length === 0) throw new NonExhaustiveError(value);
+    return results;
+  }
+
+  private evaluate(value: input): output[] {
+    const results: output[] = [];
+
+    for (const entry of this.entries) {
+      if ('tap' in entry) {
+        results.forEach(entry.tap);
+        continue;
+      }
+
+      const match = this.matchClause(entry, value);
+      if (match.matched) results.push(entry.handler(match.selection, value) as output);
+    }
+
+    return results;
+  }
+
+  private matchClause(clause: Clause, value: input): { matched: boolean; selection: unknown } {
+    for (const pattern of clause.patterns) {
+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const select = (key: string, selectedValue: unknown) => {
+        hasSelections = true;
+        selected[key] = selectedValue;
+      };
